import React from 'react';

const SearchBox = () => {
  
  // Usamos un div como contenedor principal (simulando form)
  return (
    // max-w-sm define el ancho máximo, que ayuda a que se vea como una "pastilla"
    <div className="relative flex items-center w-full max-w-sm" role="search">
      {/* 1. Ícono de búsqueda posicionado a la izquierda */}
      <i className="fas fa-search absolute left-3 text-gray-400"></i>
      
      {/* 2. Campo de Input Estático */}
      <input
        type="text"
        name="q"
        placeholder="Buscar productos..."
        // CLASES CRÍTICAS PARA EL DISEÑO DE PASTILLA:
        // *** IMPORTANTE: Usamos rounded-full ***
        className="w-full h-10 py-0 pl-10 pr-4 rounded-full border-0 shadow-sm 
          bg-white text-gray-900 placeholder-gray-500 focus:outline-none 
          focus:ring-2 focus:ring-[var(--cta-color)] focus:border-transparent 
          transition-all duration-200"
        aria-label="Buscar productos"
        // Atributos estáticos
        defaultValue="" 
        readOnly 
      />
      
    </div>
  );
};

export default SearchBox;
